class Solution:
    def smallestNumber(self, pattern: str) -> str:
        nums = [i for i in range(1, 10)]
        res = []
        for p in pattern:
            if p == 'I':
                res.append(str(nums.pop(0)))
            else:
                res.append(str(nums.pop()))
        res.append(str(nums[0]))
        return ''.join(res)
